import React from 'react';
import { 
    DocumentDuplicateIcon, 
    PencilIcon, 
    TrashIcon, 
    EyeIcon, 
    FloppyDiskIcon, 
    XCircleIcon, 
    CalendarIcon, 
    ChartBarIcon 
} from '../Icons';
import { SavedReport, Language } from '../../types';

interface ReportRowProps {
    report: SavedReport;
    isEditing: boolean;
    editName: string;
    setEditName: (val: string) => void;
    onSaveEdit: (id: string) => void;
    onCancelEdit: () => void;
    onStartEdit: (report: SavedReport) => void;
    onView: (id: string) => void;
    onDelete: (id: string, name: string) => void;
    formatDate: (iso: string, lang: Language) => string;
    language: Language;
}

export const ReportRow: React.FC<ReportRowProps> = ({
    report,
    isEditing,
    editName,
    setEditName,
    onSaveEdit,
    onCancelEdit,
    onStartEdit,
    onView,
    onDelete,
    formatDate,
    language
}) => {
    const handleKeyDown = (e: React.KeyboardEvent) => {
        if (e.key === 'Enter') onSaveEdit(report.id);
        else if (e.key === 'Escape') onCancelEdit();
    };

    return (
        <tr className="group hover:bg-slate-50/50 dark:hover:bg-slate-700/20 transition-all duration-300">
            <td className="px-6 py-2.5">
                <div className="flex items-center gap-3">
                    <div className="w-8 h-8 rounded-lg bg-blue-50 dark:bg-blue-900/20 text-brand-blue border border-blue-100 dark:border-blue-800 flex items-center justify-center shrink-0 shadow-sm group-hover:scale-105 transition-transform duration-300">
                        <DocumentDuplicateIcon className="w-4 h-4 stroke-[1.5]" />
                    </div>

                    {isEditing ? (
                        <div className="flex items-center gap-2 flex-1">
                            <input 
                                type="text" 
                                value={editName} 
                                onChange={(e) => setEditName(e.target.value)}
                                onKeyDown={handleKeyDown}
                                autoFocus
                                className="w-full text-xs font-bold text-brand-graphite dark:text-white bg-white dark:bg-slate-900 border border-brand-blue rounded-lg px-2 py-1.5 focus:ring-2 focus:ring-brand-blue/20 outline-none shadow-sm"
                            />
                            <button onClick={() => onSaveEdit(report.id)} className="p-1.5 rounded-lg text-emerald-600 bg-emerald-50 hover:bg-emerald-100 transition-colors" title="Salvar">
                                <FloppyDiskIcon className="w-3.5 h-3.5" />
                            </button>
                            <button onClick={onCancelEdit} className="p-1.5 rounded-lg text-red-500 bg-red-50 hover:bg-red-100 transition-colors" title="Cancelar">
                                <XCircleIcon className="w-3.5 h-3.5" />
                            </button>
                        </div>
                    ) : (
                        <div className="flex flex-col min-w-0 group/edit relative pr-6">
                            <div className="flex items-center gap-2">
                                <span className="text-xs font-bold text-slate-800 dark:text-slate-100 truncate cursor-default group-hover:text-brand-blue transition-colors">
                                    {report.name}
                                </span>
                                <button 
                                    onClick={() => onStartEdit(report)}
                                    className="opacity-0 group-hover/edit:opacity-100 p-1 text-slate-400 hover:text-brand-blue transition-all"
                                    title="Renomear"
                                >
                                    <PencilIcon className="w-3 h-3" />
                                </button>
                            </div>
                            <span className="text-[9px] text-slate-400 dark:text-slate-500 font-medium truncate">
                                ID: {report.id.substring(0, 12)}...
                            </span>
                        </div>
                    )}
                </div>
            </td>

            <td className="px-6 py-2.5">
                <div className="flex items-center gap-2 text-slate-500 dark:text-slate-400">
                    <CalendarIcon className="w-3 h-3" />
                    <span className="text-[10px] font-bold font-mono">
                        {formatDate(report.createdAt, language)}
                    </span>
                </div>
            </td>

            <td className="px-6 py-2.5 text-center">
                <span className="inline-flex items-center gap-1.5 px-2.5 py-0.5 rounded-full text-[9px] font-bold bg-slate-100 dark:bg-slate-700/50 text-slate-600 dark:text-slate-300 border border-slate-200 dark:border-slate-600">
                    <ChartBarIcon className="w-3 h-3 text-slate-400" />
                    {report.recordCount}
                </span>
            </td>

            <td className="px-6 py-2.5">
                <div className="flex items-center justify-center gap-2">
                    <button
                        onClick={() => onView(report.id)}
                        className="flex items-center gap-1.5 px-4 py-1.5 text-[9px] font-bold text-white bg-gradient-to-r from-sky-700 to-cyan-500 hover:from-sky-600 hover:to-cyan-400 rounded-full shadow-lg shadow-sky-500/30 hover:-translate-y-0.5 transition-all active:scale-95 uppercase tracking-wide border border-white/10"
                    >
                        <EyeIcon className="w-3.5 h-3.5" />
                        Visualizar
                    </button>
                    <button
                        onClick={() => onDelete(report.id, report.name)}
                        className="p-1.5 rounded-full text-slate-400 hover:text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20 transition-all hover:scale-110"
                        title="Excluir"
                    >
                        <TrashIcon className="w-3.5 h-3.5 stroke-[2]" />
                    </button>
                </div>
            </td>
        </tr>
    );
};

import React from 'react';
import { ChevronUpIcon, ChevronDownIcon, SearchIcon } from '../Icons';
import { SortKey, SortDirection } from '../../hooks/useSavedReportsController';
import { ReportRow } from './ReportRow';
import { SavedReport, Language } from '../../types';

interface ReportsTableProps {
    reports: SavedReport[];
    sortConfig: { key: SortKey; direction: SortDirection };
    onSort: (key: SortKey) => void;
    editingReportId: string | null;
    editName: string;
    setEditName: (val: string) => void;
    onSaveEdit: (id: string) => void;
    onCancelEdit: () => void;
    onStartEdit: (report: SavedReport) => void;
    onView: (id: string) => void;
    onDelete: (id: string, name: string) => void;
    formatDate: (iso: string, lang: Language) => string;
    language: Language;
    noResultsText: string;
}

const SortHeader: React.FC<{ 
    label: string, 
    sortKey: SortKey, 
    currentSort: { key: SortKey, direction: SortDirection }, 
    onSort: (key: SortKey) => void,
    className?: string
}> = ({ label, sortKey, currentSort, onSort, className = "" }) => {
    const isActive = currentSort.key === sortKey;
    return (
        <th className={`px-6 py-3 ${className}`}>
            <button onClick={() => onSort(sortKey)} className="flex items-center gap-1.5 text-[10px] font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest group focus:outline-none w-full justify-start">
                {label}
                {isActive ? (
                    currentSort.direction === 'asc' 
                        ? <ChevronUpIcon className="w-3 h-3 text-brand-blue" />
                        : <ChevronDownIcon className="w-3 h-3 text-brand-blue" />
                ) : (
                    <ChevronDownIcon className="w-3 h-3 opacity-30 group-hover:opacity-60" />
                )}
            </button>
        </th>
    );
};

export const ReportsTable: React.FC<ReportsTableProps> = ({
    reports,
    sortConfig,
    onSort,
    editingReportId,
    editName,
    setEditName,
    onSaveEdit,
    onCancelEdit,
    onStartEdit,
    onView,
    onDelete,
    formatDate,
    language,
    noResultsText
}) => (
    <div className="flex-1 bg-white dark:bg-slate-800 rounded-2xl shadow-card border border-slate-200 dark:border-slate-700 overflow-hidden flex flex-col">
        <div className="flex-1 overflow-auto custom-scrollbar">
            <table className="w-full text-left border-collapse">
                <thead className="bg-slate-50/80 dark:bg-slate-900/50 sticky top-0 backdrop-blur-sm z-10 border-b border-slate-100 dark:border-slate-700">
                    <tr>
                        <SortHeader label="Nome do Relatório" sortKey="name" currentSort={sortConfig} onSort={onSort} className="w-[45%]" />
                        <SortHeader label="Criado em" sortKey="createdAt" currentSort={sortConfig} onSort={onSort} className="w-[20%]" />
                        <SortHeader label="Registros" sortKey="recordCount" currentSort={sortConfig} onSort={onSort} className="w-[15%]" />
                        <th className="px-6 py-3 w-[20%] text-center text-[10px] font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest">
                            Ações
                        </th>
                    </tr>
                </thead>
                <tbody className="divide-y divide-slate-50 dark:divide-slate-700/50">
                    {reports.length > 0 ? (
                        reports.map((report) => (
                            <ReportRow 
                                key={report.id}
                                report={report}
                                isEditing={editingReportId === report.id}
                                editName={editName}
                                setEditName={setEditName}
                                onSaveEdit={onSaveEdit}
                                onCancelEdit={onCancelEdit}
                                onStartEdit={onStartEdit}
                                onView={onView}
                                onDelete={onDelete}
                                formatDate={formatDate}
                                language={language}
                            />
                        ))
                    ) : (
                        <tr>
                            <td colSpan={4} className="py-20 text-center">
                                <div className="flex flex-col items-center justify-center text-slate-400 dark:text-slate-500">
                                    <SearchIcon className="w-10 h-10 mb-2 opacity-20" />
                                    <p className="text-xs font-bold">{noResultsText}</p>
                                    <p className="text-[10px] mt-0.5 opacity-70">Tente ajustar sua busca.</p>
                                </div>
                            </td>
                        </tr>
                    )}
                </tbody>
            </table>
        </div>
    </div>
);

import React from 'react';
import { useUI } from '../contexts/UIContext';
import { EmptyState } from '../components/EmptyState';
import { DocumentDuplicateIcon } from '../components/Icons';
import { useSavedReportsController } from '../hooks/useSavedReportsController';
import { SavedReportsHeader } from '../components/saved-reports/SavedReportsHeader';
import { ReportsTable } from '../components/saved-reports/ReportsTable';

/**
 * SAVED REPORTS VIEW (V3 - MODULAR REFACTORED)
 * Orchestrates listing and management of saved reconciliation history.
 */
export const SavedReportsView: React.FC = () => {
    const ctrl = useSavedReportsController();
    const { setActiveView } = useUI();

    if (ctrl.savedReports.length === 0) {
        return (
            <div className="flex-1 flex items-center justify-center">
                <EmptyState
                    icon={<DocumentDuplicateIcon className="w-12 h-12 text-brand-blue dark:text-blue-400" />}
                    title={ctrl.t('savedReports.empty.title')}
                    message={ctrl.t('savedReports.empty.message')}
                    action={{
                        text: ctrl.t('empty.dashboard.action'), 
                        onClick: () => setActiveView('upload'),
                    }}
                />
            </div>
        );
    }

    return (
        <div className="flex flex-col h-full animate-fade-in gap-2 pb-1">
            <SavedReportsHeader 
                title={ctrl.t('savedReports.title')}
                searchPlaceholder={ctrl.t('savedReports.search')}
                searchQuery={ctrl.searchQuery}
                onSearchChange={ctrl.setSearchQuery}
                usagePercent={ctrl.usagePercent}
                storageColor={ctrl.storageColor}
                currentCount={ctrl.savedReports.length}
                maxCount={ctrl.maxSavedReports}
            />

            <ReportsTable 
                reports={ctrl.processedReports}
                sortConfig={ctrl.sortConfig}
                onSort={ctrl.handleSort}
                editingReportId={ctrl.editingReportId}
                editName={ctrl.editName}
                setEditName={ctrl.setEditName}
                onSaveEdit={ctrl.handleSaveEdit}
                onCancelEdit={ctrl.handleCancelEdit}
                onStartEdit={ctrl.handleStartEdit}
                onView={ctrl.viewSavedReport}
                onDelete={(id, name) => ctrl.openDeleteConfirmation({ type: 'report-saved', id, name })}
                formatDate={ctrl.formatDate}
                language={ctrl.language}
                noResultsText={ctrl.t('common.noResults')}
            />
        </div>
    );
};
